const body = $json.body || $json;
const { city, business_type, client_id, plan } = body;

if (!city || !business_type || !client_id) {
  throw new Error('Missing required fields: city, business_type, client_id');
}

// ADDED: Validate client_id format — alphanumeric + underscores, 4-64 chars
const clientIdRegex = /^[a-zA-Z0-9_]{4,64}$/;
if (!clientIdRegex.test(client_id)) {
  throw new Error('Invalid client_id format. Must be 4-64 alphanumeric characters (underscores allowed).');
}

return [{
  json: {
    city,
    business_type,
    client_id,
    plan: plan || 'free',
    max_leads: plan === 'pro' ? 100 : plan === 'basic' ? 30 : 10,
    timestamp: new Date().toISOString()
  }
}];

let keywords;
try {
  const raw = $json.text || $json.choices?.[0]?.message?.content || '';
  keywords = JSON.parse(raw);
} catch (e) {
  keywords = [$json.city + ' ' + $json.business_type + ' contact email'];
}

const prevJson = $('Validate Input').first().json;

return keywords.map(keyword => ({
  json: {
    ...prevJson,
    keyword
  }
}));

const results = Array.isArray($input.all()) ? $input.all() : [$input.first()];
const urls = [];

// IMPROVED: Extended blacklist to filter non-lead aggregator/social sites
const BLACKLIST = [
  'google.', 'youtube.', 'facebook.com', 'instagram.com',
  'yelp.com', 'linkedin.com', 'twitter.com', 'x.com',
  'justdial.com', 'indiamart.com', 'sulekha.com', 'wikipedia.org',
  'tripadvisor.com', 'zomato.com', 'practo.com', 'quora.com'
];

for (const item of results) {
  const data = item.json;
  const url = data.url || '';
  const isBlacklisted = BLACKLIST.some(b => url.includes(b));
  if (url.startsWith('http') && !isBlacklisted) {
    urls.push({
      json: {
        website: url,
        title: data.title || '',
        description: data.description || '',
        client_id: $('Validate Input').first().json.client_id,
        city: $('Validate Input').first().json.city,
        business_type: $('Validate Input').first().json.business_type
      }
    });
  }
}

return urls.length > 0 ? urls : [{ json: { website: null, skip: true } }];

const html = $json.data || $json.body || '';
const prev = $('Filter Valid URLs').first().json;

// IMPROVED: International email regex (unchanged — handled by AI for obfuscated variants)
const emailRegex = /[A-Z0-9._%+\-]+@[A-Z0-9.\-]+\.[A-Z]{2,}/ig;

// IMPROVED: International phone regex — covers IN (+91), US (+1), UK (+44), EU (+3x/+4x/+5x),
// and generic 7–15 digit numbers with optional country code prefix
const phoneRegex = /(?:\+?(?:1|44|91|49|33|39|34|61|81|86|55|27|\d{1,3})[\-\s]?)?(?:\(?\d{2,4}\)?[\-\s]?){2,4}\d{3,4}(?!\d)/g;

const linkedinRegex = /https?:\/\/(?:www\.)?linkedin\.com\/(?:in|company)\/[A-Za-z0-9\-_]+/g;

const emails = [...new Set(html.match(emailRegex) || [])];
const rawPhones = html.match(phoneRegex) || [];
// Filter out numbers that look like years or short codes (less than 7 digits)
const phones = [...new Set(rawPhones.filter(p => p.replace(/\D/g, '').length >= 7))];
const linkedins = [...new Set(html.match(linkedinRegex) || [])];

return [{
  json: {
    website: prev.website,
    title: prev.title,
    description: prev.description,
    city: prev.city,
    business_type: prev.business_type,
    client_id: prev.client_id,
    raw_html_snippet: html.substring(0, 5000),
    emails,
    phones,
    linkedins,
    has_contact: emails.length > 0 || phones.length > 0
  }
}];

