let enriched;
try {
  const raw = $json.text || $json.choices?.[0]?.message?.content || '{}';
  enriched = JSON.parse(raw);
} catch (e) {
  enriched = {};
}

const prev = $('Extract Contacts').first().json;

// GATEKEEPER: If company_name is null/empty, score = 0 (junk lead — AI enrichment failed)
if (!enriched.company_name || enriched.company_name.trim() === '' || enriched.company_name === 'null') {
  return [{
    json: {
      ...enriched,
      client_id: prev.client_id,
      city: prev.city,
      business_type: prev.business_type,
      linkedin: null,
      score: 0,
      status: 'Cold',
      discard_reason: 'company_name_null',
      source: '_Auto',
      created_at: new Date().toISOString()
    }
  }];
}

let score = 0;
if (enriched.primary_email) score += 30;
if (enriched.primary_phone) score += 25;
if (enriched.contact_quality === 'high') score += 25;
else if (enriched.contact_quality === 'medium') score += 15;
if (prev.linkedins && prev.linkedins.length > 0) score += 10;
if (enriched.website) score += 10;

const status = score >= 70 ? 'Hot' : score >= 40 ? 'Warm' : 'Cold';

return [{
  json: {
    ...enriched,
    client_id: prev.client_id,
    city: prev.city,
    business_type: prev.business_type,
    linkedin: (prev.linkedins || [])[0] || null,
    score,
    status,
    source: '_Auto',
    created_at: new Date().toISOString()
  }
}];

