return items.map(item => {
  const j = item.json || {};
  const headers = (j.headers && typeof j.headers === 'object') ? j.headers : {};
  const sigHeader = headers['x-signature'] || headers['x-signature-256'] || headers['stripe-signature'] || '';
  const raw = j.rawBody || j.__raw || '';
  let secret = '';
  try { if (typeof $env !== 'undefined' && $env.LEADYX_WEBHOOK_SECRET) secret = $env.LEADYX_WEBHOOK_SECRET; } catch(e) {}
  if (!secret && typeof process !== 'undefined' && process.env && process.env.LEADYX_WEBHOOK_SECRET) { secret = process.env.LEADYX_WEBHOOK_SECRET }
  let ok = true, enforced = false, reason = 'not_configured';
  if (secret && sigHeader && raw) {
    try {
      const crypto = require('crypto');
      const received = String(sigHeader);
      const prefix = 'sha256=';
      const receivedHex = received.startsWith(prefix) ? received.slice(prefix.length) : received;
      const expected = crypto.createHmac('sha256', secret).update(raw, 'utf8').digest('hex');
      const a = Buffer.from(expected, 'hex');
      const b = Buffer.from(receivedHex, 'hex');
      ok = (a.length === b.length) && crypto.timingSafeEqual(a,b);
      enforced = true; reason = ok ? 'ok' : 'mismatch';
    } catch(err) {
      ok = true; enforced = false; reason = 'crypto_unavailable';
    }
  }
  item.json = Object.assign({}, j, { _sig: { ok, enforced, reason } });
  return item;
});

return items.map(item => {
  const j = item.json || {};
  if (!j.correlationId) {
    const rnd = Math.random().toString(16).slice(2,10);
    const ts = Date.now().toString(36);
    j.correlationId = `leadyx_${ts}_${rnd}`;
  }
  item.json = j;
  return item;
});
